import acm.program.*;
import acm.graphics.*;
import java.awt.*;

public class BouncingBall extends GraphicsProgram {
    private static final int DIAM = 30;
    private static final double FPS = 60.0;
    public void run() {
        GOval ball = new GOval(DIAM, DIAM);
        ball.setFilled(true);
        ball.setFillColor(Color.RED);
        add(ball, getWidth() / 2.0 - DIAM / 2.0, getHeight() / 2.0 - DIAM / 2.0);
        double dx = 3.0, dy = 2.5;
        while (true) {
            ball.move(dx, dy);
            if (ball.getX() <= 0 || ball.getX() + DIAM >= getWidth()) {
                dx = -dx;
            }
            if (ball.getY() <= 0 || ball.getY() + DIAM >= getHeight()) {
                dy = -dy;
            }
            pause(1000.0 / FPS);
        }
    }
}

import acm.program.*;
import acm.graphics.*;
import java.awt.event.*;
import java.awt.*;

public class DragDemo extends GraphicsProgram {
    private GObject selected = null;
    private double offsetX, offsetY;

    public void run() {
        GRect box = new GRect(100, 60);
        box.setFilled(true); box.setFillColor(Color.CYAN);
        add(box, 80, 80);
        GOval puck = new GOval(60, 60);
        puck.setFilled(true); puck.setFillColor(Color.MAGENTA);
        add(puck, 220, 140);
        addMouseListeners();
    }

    public void mousePressed(MouseEvent e) {
        selected = getElementAt(e.getX(), e.getY());
        if (selected != null) {
            offsetX = e.getX() - selected.getX();
            offsetY = e.getY() - selected.getY();
        }
    }

    public void mouseDragged(MouseEvent e) {
        if (selected != null) {
            selected.setLocation(e.getX() - offsetX, e.getY() - offsetY);
        }
    }

    public void mouseReleased(MouseEvent e) {
        selected = null;
    }
}

import acm.program.*;
import acm.graphics.*;
import java.awt.*;
import java.awt.event.*;

public class MiniBreakout extends GraphicsProgram {
    private static final int WIDTH = 400, HEIGHT = 600;
    private static final int PADDLE_W = 60, PADDLE_H = 10;
    private static final int DIAM = 12;
    private static final double FPS = 60.0;

    private GRect paddle;
    private GOval ball;
    private double dx = 3.0, dy = 3.5;

    public void run() {
        setSize(WIDTH, HEIGHT);
        setupPaddle();
        setupBall();
        addMouseListeners();
        while (true) {
            ball.move(dx, dy);
            // Wall bounces
            if (ball.getX() <= 0 || ball.getX() + DIAM >= getWidth()) dx = -dx;
            if (ball.getY() <= 0) dy = -dy;
            if (ball.getY() + DIAM >= getHeight()) {
                // reset ball
                ball.setLocation(getWidth() / 2.0 - DIAM / 2.0, getHeight() / 2.0 - DIAM / 2.0);
                dx = 3.0; dy = 3.5;
            }
            // Collision sampling
            GObject hit = checkBallCollision();
            if (hit == paddle) {
                dy = -Math.abs(dy);
                // Optional: tweak dx based on where the ball hits the paddle
            }
            pause(1000.0 / FPS);
        }
    }

    private void setupPaddle() {
        paddle = new GRect(PADDLE_W, PADDLE_H);
        paddle.setFilled(true); paddle.setFillColor(Color.BLACK);
        add(paddle, getWidth() / 2.0 - PADDLE_W / 2.0, getHeight() - 40);
    }

    private void setupBall() {
        ball = new GOval(DIAM, DIAM);
        ball.setFilled(true); ball.setFillColor(Color.RED);
        add(ball, getWidth() / 2.0 - DIAM / 2.0, getHeight() / 2.0 - DIAM / 2.0);
    }

    private GObject checkBallCollision() {
        double x = ball.getX();
        double y = ball.getY();
        GObject obj;
        // bottom-center
        obj = getElementAt(x + DIAM / 2.0, y + DIAM + 1);
        if (obj != null) return obj;
        // left side
        obj = getElementAt(x - 1, y + DIAM / 2.0);
        if (obj != null) { dx = Math.abs(dx); return obj; }
        // right side
        obj = getElementAt(x + DIAM + 1, y + DIAM / 2.0);
        if (obj != null) { dx = -Math.abs(dx); return obj; }
        return null;
    }

    public void mouseMoved(MouseEvent e) {
        double newX = e.getX() - PADDLE_W / 2.0;
        newX = Math.max(0, Math.min(newX, getWidth() - PADDLE_W));
        paddle.setLocation(newX, paddle.getY());
    }
}
